UPDATE EVA_FILE
SET
	FILE_SEQ = #{fileSeq}
WHERE
	FILE_ID = #{fileId}
	AND FILE_SEQ = #{orginFileSeq}

mapper.delete:

DELETE EVA_FILE
WHERE
	FILE_ID = #{fileId}
	AND FILE_SEQ >= #{fileSeq}

mapper.insert:


			SELECT 'H' || LPAD(EVA_HIS_SEQ.NEXTVAL, 13, '0') AS HIS_NO FROM DUAL

        INSERT INTO EVA_HIS (
        	HIS_NO, MENU_NO, MENU_NM, WORK_TYPE, FUNC_NM, UNIV_NM, RMRK, RESULT_TYPE, LINK, PRIVACY_YN, PRIVACY_INFO, INPT_DT, INPT_ID, INPT_NM, INPT_USR_NO, USR_IP, SESSION_ID, URI
        ) VALUES (
        	#{HIS_NO}, #{MENU_NO}, #{MENU_NM}, #{WORK_TYPE}, #{FUNC_NM}, #{UNIV_NM}, #{RMRK}, #{RESULT_TYPE}, #{LINK}, #{PRIVACY_YN}, #{PRIVACY_INFO}, sysdate, #{sessUsrId}, #{sessUsrNm}, #{sessUsrNo}, #{usrIp}, #{sessionId}, #{uri}
        )

mapper.update:
UPDATE EVA_HIS
SET
	RESULT_TYPE = #{RESULT_TYPE}
	, RESULT = #{RESULT}
	, PARAM = #{PARAM}
	, RMRK = #{RMRK}
	, INPT_ID = #{usrId}
	, INPT_NM = #{usrNm}
	, INPT_USR_NO = #{usrNo}
	, LAST_CHG_DT = SYSDATE
WHERE
	HIS_NO = #{HIS_NO}

mapper.select:
SELECT TRAN_CORS_CD , (SELECT CODE_NM FROM EVA_CODE WHERE CODE = SBJT.TRAN_CORS_CD) TRAN_CORS_NM FROM EVA_SCSBJT SBJT
SBJT.UNIV_CD = #{univCd}
AND SBJT.ABOL_YN = #{abolYn}
GROUP BY TRAN_CORS_CD ORDER BY TRAN_CORS_CD

SELECT SCSBJT_NO , SCSBJT_NM FROM (
SELECT SCSBJT_NO , CASE WHEN SBJT.ABOL_YN = 'Y' THEN '(폐지) ' || SBJT.SCSBJT_NM ELSE SBJT.SCSBJT_NM END SCSBJT_NM , SBJT.ABOL_YN FROM EVA_SCSBJT SBJT
SBJT.UNIV_CD = #{univCd} AND SBJT.TRAN_CORS_CD = #{tranCorsCd}
AND SBJT.ABOL_YN = #{abolYn}
) A ORDER BY CASE WHEN ABOL_YN = 'N' THEN '1' ELSE '2' END , SCSBJT_NM , SCSBJT_NO

SELECT SBJT.SCSBJT_NO , SBJT.SCSBJT_NM FROM EVA_SCSBJT SBJT LEFT OUTER JOIN ( SELECT P_NUM , APRV_REQ_NO , SCSBJT_NO , APRV_REQ_CD , APRV_REQ_REASON , APRV_YNCW , APRV_REASON , OFFIC_DOC_RCV_DT , RST_NOTIFC_DT , REQ_DT , REQ_ID , INPT_DT , INPT_ID FROM ( SELECT ROW_NUMBER() OVER (PARTITION BY SCSBJT_NO ORDER BY APRV_REQ_NO DESC) P_NUM , APRV_REQ_NO , SCSBJT_NO , APRV_REQ_CD , APRV_REQ_REASON , APRV_YNCW , APRV_REASON , TO_CHAR(OFFIC_DOC_RCV_DT, 'YYYY.MM.DD HH24:MI') OFFIC_DOC_RCV_DT , TO_CHAR(RST_NOTIFC_DT, 'YYYY.MM.DD HH24:MI') RST_NOTIFC_DT , TO_CHAR(REQ_DT, 'YYYY.MM.DD HH24:MI') REQ_DT , REQ_ID , TO_CHAR(INPT_DT, 'YYYY.MM.DD HH24:MI') INPT_DT , INPT_ID FROM EVA_SCSBJT_APRV_REQ WHERE TO_CHAR(INPT_DT, 'YYYY') = TO_CHAR(SYSDATE, 'YYYY') --해당연도의 마지막 요청값을 가져옴 ) WHERE P_NUM = 1 AND APRV_YNCW = 'W' ) REQ ON SBJT.SCSBJT_NO = REQ.SCSBJT_NO WHERE SBJT.UNIV_CD = #{univCd}
AND SBJT.TRAN_CORS_CD = #{tranCorsCd}
AND SBJT.ABOL_YN = #{abolYn} AND REQ.APRV_REQ_NO IS NULL
ORDER BY SBJT.SCSBJT_NM

mapper.insert:

INSERT INTO EVA_DATA_MAP (
	GROUP_CD, MAIN_CODE, SUB_CODE, SPARE1, SPARE2, SPARE3, INPT_DT, INPT_ID
) VALUES (
	#{groupCd}, #{mainCode}, #{subCode}, #{spare1}, #{spare2}, #{spare3}, sysdate, #{sessUsrId}
)


DELETE FROM EVA_DATA_MAP
WHERE
	GROUP_CD = #{groupCd}
	AND SUB_CODE = #{subCode}

mapper.select:
SELECT SBJT.TRAN_CORS_CD , (SELECT CODE_NM FROM EVA_CODE WHERE CODE = SBJT.TRAN_CORS_CD) TRAN_CORS_NM FROM EVA_SCSBJT SBJT LEFT OUTER JOIN EVA_TARGET_SCSBJT_REQ TREQ ON SBJT.SCSBJT_NO = TREQ.SCSBJT_NO AND TREQ.CYCL = #{cycl}
SBJT.UNIV_CD = #{univCd}
AND SBJT.ABOL_YN = 'N' AND TREQ.APRV_YN = 'Y'
GROUP BY SBJT.TRAN_CORS_CD ORDER BY SBJT.TRAN_CORS_CD

SELECT SBJT.SCSBJT_NO , SBJT.SCSBJT_NM FROM EVA_SCSBJT SBJT LEFT OUTER JOIN EVA_TARGET_SCSBJT_REQ TREQ ON SBJT.SCSBJT_NO = TREQ.SCSBJT_NO AND TREQ.CYCL = #{cycl}
SBJT.UNIV_CD = #{univCd} AND SBJT.TRAN_CORS_CD = #{tranCorsCd} AND SBJT.ABOL_YN = 'N' AND TREQ.APRV_YN = 'Y'
ORDER BY SBJT.SCSBJT_NM , SBJT.SCSBJT_NO

mapper.insert:
INSERT INTO EVA_LOGIN_USR (
	SESSION_ID, USR_NO, USR_ID, USR_NM, USR_PERM_NM, UNIV_NM, PIC_NO, INPT_DT, LAST_ACCESS_DT, MAX_INTERVAL
) VALUES (
	#{sessId}, #{usrNo}, #{usrId}, #{usrNm}, #{usrPermNm}, #{univNm}, #{picNo}, sysdate, sysdate, #{maxInterval}
)

mapper.update:
        UPDATE EVA_LOGIN_USR
        SET LAST_ACCESS_DT = SYSDATE
        WHERE
        	SESSION_ID = #{sessId}
        	AND USR_NO = #{usrNo}

				AND PIC_NO = #{picNo}

mapper.select:

        SELECT
        	COUNT(*)
        FROM 
        	EVA_LOGIN_USR 
        WHERE
        	SESSION_ID = #{sessId} 
        	AND USR_NO = #{usrNo}

				AND PIC_NO = #{picNo}

mapper.delete:

      	DELETE FROM EVA_LOGIN_USR 

	      	USR_NO = #{usrNo}

				AND PIC_NO = #{picNo}

mapper.select:
SELECT YEAR FROM EVA_METRICS_MAP M INNER JOIN EVA_SCSBJT2 SBJT ON M.SCSBJT_NO = SBJT.SCSBJT_NO AND SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd} INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD INNER JOIN EVA_METRICS METRIC ON M.METRIC_CD = METRIC.METRIC_CD
AND SBJT.UNIV_CD = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
AND METRIC.METRIC_NM =#{metricNm}
AND METRIC.METRIC_CD =#{metricCd}
GROUP BY YEAR ORDER BY YEAR

SELECT CALC_YEAR FROM EVA_METRICS_MAP M INNER JOIN EVA_SCSBJT2 SBJT ON M.SCSBJT_NO = SBJT.SCSBJT_NO AND SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd} INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD
CALC_YEAR IS NOT NULL
AND SBJT.UNIV_CD = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
GROUP BY CALC_YEAR ORDER BY CALC_YEAR

SELECT UNIV.UNIV_CD, UNIV.UNIV_NM FROM EVA_SCSBJT2 SBJT INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD
INNER JOIN EVA_UNIV_PERM_MAP UPMAP ON UPMAP.UNIV_CD = UNIV.UNIV_CD AND UPMAP.MENU_ID = #{menuId} INNER JOIN EVA_USR USR ON UPMAP.UNIV_PERM_NM = USR.UNIV_PERM_NM AND USR.USR_NO = #{usrNo}
WHERE SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd}
AND SBJT.UNIV_CD = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
GROUP BY UNIV.UNIV_CD, UNIV.UNIV_NM ORDER BY UNIV.UNIV_NM

SELECT SBJT.TRAN_CORS_CD , (SELECT CODE_NM FROM EVA_CODE WHERE CODE = SBJT.TRAN_CORS_CD) TRAN_CORS_NM FROM EVA_METRICS_MAP M INNER JOIN EVA_SCSBJT2 SBJT ON M.SCSBJT_NO = SBJT.SCSBJT_NO AND SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd} INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD
AND SBJT.UNIV_CD = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
GROUP BY SBJT.TRAN_CORS_CD ORDER BY SBJT.TRAN_CORS_CD

SELECT SBJT.SCSBJT_NO , SBJT.SCSBJT_NM FROM EVA_METRICS_MAP M INNER JOIN EVA_SCSBJT2 SBJT ON M.SCSBJT_NO = SBJT.SCSBJT_NO AND SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd} INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD
AND SBJT.UNIV_CD = #{univCd}
AND SBJT.TRAN_CORS_CD = #{tranCorsCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
GROUP BY SBJT.SCSBJT_NO , SBJT.SCSBJT_NM ORDER BY SBJT.SCSBJT_NM

SELECT SBJT.TRAN_CORS_CD , (SELECT CODE_NM FROM EVA_CODE WHERE CODE = SBJT.TRAN_CORS_CD) TRAN_CORS_NM FROM EVA_METRICS_MAP M INNER JOIN EVA_SCSBJT2 SBJT ON M.SCSBJT_NO = SBJT.SCSBJT_NO AND SBJT.LAST_YN = 'Y' AND SBJT.CYCL_CD = #{cyclCd} INNER JOIN EVA_UNIV UNIV ON SBJT.UNIV_CD = UNIV.UNIV_CD
SBJT.TRAN_CORS_CD IN ('10060009', '10060010', '10060011', '10060012', '10060013')
AND SBJT.UNIV_CD = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
GROUP BY SBJT.TRAN_CORS_CD ORDER BY SBJT.TRAN_CORS_CD

SELECT TRAN_CORS_CD , TRAN_CORS_NM FROM ( SELECT TCH.TCH_NO , TCH.SCSBJT_NO , CASE WHEN SUBSTR(TCH.SCSBJT_NO , INSTR(TCH.SCSBJT_NO, '-') + 1, 4) = '9999' THEN '99999999' ELSE (SELECT TRAN_CORS_CD FROM EVA_SCSBJT2 WHERE SCSBJT_NO = TCH.SCSBJT_NO AND CYCL_CD = #{cyclCd}) END TRAN_CORS_CD , CASE WHEN SUBSTR(TCH.SCSBJT_NO , INSTR(TCH.SCSBJT_NO, '-') + 1, 4) = '9999' THEN '기타' ELSE (SELECT CODE_NM FROM EVA_CODE WHERE CODE = (SELECT TRAN_CORS_CD FROM EVA_SCSBJT2 WHERE SCSBJT_NO = TCH.SCSBJT_NO AND CYCL_CD = #{cyclCd})) END TRAN_CORS_NM FROM EVA_TCH TCH INNER JOIN EVA_UNIV UNIV ON SUBSTR(TCH.TCH_NO,2,8) = UNIV.UNIV_CD
AND SUBSTR(TCH.TCH_NO,2,8) = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
) GROUP BY TRAN_CORS_CD , TRAN_CORS_NM ORDER BY TRAN_CORS_CD

SELECT SCSBJT_NO , SCSBJT_NM FROM ( SELECT TCH.TCH_NO , TCH.SCSBJT_NO , CASE WHEN SUBSTR(TCH.SCSBJT_NO , INSTR(TCH.SCSBJT_NO, '-') + 1, 4) = '9999' THEN TCH.SCSBJT_NM_DIRECT ELSE (SELECT SCSBJT_NM FROM EVA_SCSBJT2 WHERE SCSBJT_NO = TCH.SCSBJT_NO AND CYCL_CD = #{cyclCd}) END SCSBJT_NM FROM EVA_TCH TCH INNER JOIN EVA_UNIV UNIV ON SUBSTR(TCH.TCH_NO,2,8) = UNIV.UNIV_CD
AND SUBSTR(TCH.TCH_NO,2,8) = #{univCd}
AND UNIV.EVA_TARGET =#{evaTargetCd}
AND TCH.SCSBJT_NM_DIRECT IS NOT NULL
AND (SELECT TRAN_CORS_CD FROM EVA_SCSBJT2 WHERE SCSBJT_NO = TCH.SCSBJT_NO AND CYCL_CD = #{cyclCd}) = #{tranCorsCd}
) GROUP BY SCSBJT_NO , SCSBJT_NM ORDER BY SCSBJT_NM
